// Normalizar respuesta de Sketchfab al formato RenderHub
const response = $input.first().json;
const results = response.results || [];
const query = $('Trigger Sub-Workflow').first().json.query || '';

const normalized = results.map(item => {
  // Extraer mejor thumbnail disponible
  const thumbs = item.thumbnails?.images || [];
  const thumb = thumbs.find(t => t.width >= 200)?.url ||
                thumbs[0]?.url || '';

  // Categorías/tags
  const tags = (item.categories || []).map(c => c.name)
    .concat((item.tags || []).map(t => t.name))
    .slice(0, 8);

  return {
    platform: 'Sketchfab',
    id: item.uid || '',
    name: item.name || '',
    description: (item.description || '').slice(0, 300),
    thumbnail_url: thumb,
    page_url: item.viewerUrl || `https://sketchfab.com/models/${item.uid}`,
    download_url: null,
    stl_direct: false,
    download_api: `https://api.sketchfab.com/v3/models/${item.uid}/download`,
    format_note: 'API entrega glTF/GLB. Para STL usar: https://sketchfab.com/3d-models/' + item.uid,
    creator: item.user?.username || '',
    likes: item.likeCount || 0,
    views: item.viewCount || 0,
    downloads: item.downloadCount || 0,
    tags
  };
});

return {
  platform: 'Sketchfab',
  query,
  count: normalized.length,
  results: normalized
};

